// Test the flexible polyline decoder
const ENCODING_CHARS = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_'
const DECODING = new Uint8Array\(256\)
for \(let i = 0; i < ENCODING_CHARS.length; i++\) {
  DECODING[ENCODING_CHARS.charCodeAt\(i\)] = i
}
function toSigned\(val\) { return val & 1 ? ~\(val >> 1\) : val >> 1 }
function decodeVarint\(encoded, index\) {
  let result = 0, shift = 0, byte
  do {
    byte = DECODING[encoded.charCodeAt\(index++\)]
    result |= \(byte & 0x1F\) << shift
    shift += 5
  } while \(byte >= 0x20\)
  return { result, index }
}
function decode\(encoded\) {
  if \(!encoded\) return []
  let index = 0
  const header = decodeVarint\(encoded, index\)
  index = header.index
  const headerVal = header.result
  const precision = headerVal & 0xF
  const factor = Math.pow\(10, precision\)
  const coords = []
  let accLat = 0, accLng = 0
  while \(index < encoded.length\) {
    const latDelta = decodeVarint\(encoded, index\); index = latDelta.index; accLat += toSigned\(latDelta.result\)
    const lngDelta = decodeVarint\(encoded, index\); index = lngDelta.index; accLng += toSigned\(lngDelta.result\)
    coords.push\([accLat / factor, accLng / factor]\)
  }
  return coords
}

