// Trace the header byte carefully
// Polyline: BGmoongD43hn6B...
// First char 'B' = index 1 in ENCODING_CHARS \(< 32, so single-byte varint\)
// header = 1
// version = 1 & 0xF = 1
// precision = \(1 >> 4\) & 0xF = 0  <- WRONG, should be 5

// What if the polyline actually starts decoding from 'G' and 'B' is something else?
// Let's try: what if first varint is 'BG' together?
// B=1 \(< 32\) -> single byte, value=1. So header=1.

// BUT: What if the correct precision IS encoded differently?
// Let's check: for precision=5, header should be:
// version=1, precision=5 -> 1 | \(5 << 4\) = 81
// 81 as varint: 81 >= 32, so multi-byte:
//   byte1 = \(81 & 31\) | 32 = 17 | 32 = 49 -> char at 49 = ?
const enc = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_'
console.log\('char at 49:', enc[49]\) // should be 'X'
console.log\('char at 2:', enc[2]\)   // 'C'
// So precision=5 header -> 'XC', not 'B'

// What does 'B'=1 mean then?
// version = 1 & 0xF = 1, precision = \(1>>4\)&0xF = 0
// factor = 10^0 = 1

// But let's also try: maybe the decoder should decode 'BG' as FIRST varint \(not 'B' alone\)
// The rule is: if value >= 32 -> continuation. B=1 < 32, so it IS complete.

// OK let's try a totally different approach: use the npm package source
// from https://github.com/heremaps/flexible-polyline/blob/master/javascript/index.js
// and decode manually

const ENCODING_TABLE = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-_'
const DECODING_TABLE = new Array\(256\).fill\(-1\)
for \(let i = 0; i < ENCODING_TABLE.length; i++\) {
  DECODING_TABLE[ENCODING_TABLE.charCodeAt\(i\)] = i
}

function decodeUnsignedValues\(encoded\) {
  let result = 0, shift = 0
  const resList = []
  for \(const char of encoded\) {
    let value = DECODING_TABLE[char.charCodeAt\(0\)]
    result |= \(value & 0x1F\) << shift
    if \(value < 0x20\) {
      resList.push\(result\)
      result = 0
      shift = 0
    } else {
      shift += 5
    }
  }
  return resList
}

